pub fn take_while<F: Fn(&T) -> bool>(self, f: F) -> Iter<T> {
    let mut result = Vec::new();
    for item in self.items {
        if f(&item) {
            result.push(item);
        } else {
            break;
        }
    }
    Iter { items: result, pos: 0 }
}

pub fn skip_while<F: Fn(&T) -> bool>(self, f: F) -> Iter<T> {
    let mut skipping = true;
    let mut result = Vec::new();
    for item in self.items {
        if skipping && f(&item) {
            continue;
        }
        skipping = false;
        result.push(item);
    }
    Iter { items: result, pos: 0 }
}
